Here's some example code:

```python
import graphene
from importlib import import_module
from graphql_relay.connection.arrayconnection import offset_to_cursor
from something_app.models import Something
from something_app.schema import SomethingNode


class CreateSomething(graphene.relay.ClientIDMutation):
    class Input:
        name = graphene.String()
        
    viewer = graphene.Field(lambda: import_module('your_app.schema').Viewer)
    something_edge = graphene.Field(SomethingNode.Connection.Edge)
    success = graphene.Boolean()

    @classmethod
    def mutate_and_get_payload(cls, input, context, info):
        name = input.get('name')

        something = Something(name=name)
        something.save()

        # hacky but works for now
        cursor = offset_to_cursor(Something.objects.count() - 1)
        edge = SomethingNode.Connection.Edge(node=something, cursor=cursor)

        return cls(viewer=import_module('your_app.schema').Viewer, edge=edge, success=bool(something.id))
```

and the client-side mutation config:
```javascript
import Relay from 'react-relay';

export default class CreateSomethingMutation extends Relay.Mutation {

  getMutation () {
    return Relay.QL`
      mutation { createSomething }
    `;
  }

  getVariables () {
    return { name: this.props.name };
  }

  getFatQuery () {
    return Relay.QL`
      fragment on CreateSomethingPayload @relay(pattern: true) {
        clientMutationId
        success
        edge {
          node {
            id
          }
        }
        viewer {
          id
          allSomethings
        }
      }
    `
  }

  getConfigs () {
    return [{
      type: 'RANGE_ADD',
      parentName: 'viewer',
      parentID: this.props.viewer.id,
      connectionName: 'allSomethings',
      edgeName: 'edge',
      rangeBehaviors: {
        '': 'append'
      }
    }];
  }
}
```

Yes, that is the intended behavior. If you want the snake_cased name (which I don't recommend you do -- keep with convention and use camelCasing) you can simply pass `name='work_order'` to the Field constructor. 

```python
 class Query(ObjectType):
    work_order = Field(WorkOrder, id=graphene.Argument(graphene.String), name='work_order')

    @resolve_only_args
    def resolve_work_order(self, id):
        return WorkOrder(id='1', state='test')

```

Hey @matthewjohnston4, the "node" resolver is a relay-specific endpoint. It is used by the relay client to prevent over-fetching. It is not intended to ever be used for anything else. In this case, you would want to create a field similar to what @khankuan showed, but there is also no need to create a CustomNode... so you could simply do:


```
class Thread(DjangoObjectType):

  @staticmethod
  def get_thread_for_id(id)
    return self._meta.model.objects.get(id=id)

  class Meta:
    model = Thread
    interfaces = (relay.Node, )


class Query(ObjectType):
  node = relay.Node.Field() # This is for relay's internal use only.
  thread = graphene.Field(Thread, id=graphene.String())
  all_threads = DjangoFilterConnectionField(Thread)

  def resolve_thread(self, args, context, info):
    return Thread.get_thread_for_id(id=args.get('id))
```

